@Test public void attributeWithUnbalancedBracketsThrows() {
    String html = "<div data='[Unbalanced'>One</div>";
    Document doc = Jsoup.parse(html);
    try {
        doc.select("div[data='[Unbalanced']");
        fail("Expected exception for unbalanced brackets");
    } catch (Selector.SelectorParseException e) {
        // expected
    }
}

@Test public void attributeWithEscapedBrackets() {
    String html = "<div data='\\[Escaped\\]'>One</div>";
    Document doc = Jsoup.parse(html);
    Elements result = doc.select("div[data='\\[Escaped\\]']");
    assertEquals(1, result.size());
    assertEquals("One", result.first().text());
}

@Test public void attributeWithNestedBrackets() {
    String html = "<div data='[[nested]]'>One</div>";
    Document doc = Jsoup.parse(html);
    Elements result = doc.select("div[data='[[nested]]']");
    assertEquals(1, result.size());
    assertEquals("One", result.first().text());
}
